import React from 'react';

const ContactUs = () => {
  return (
    <div className="p-8">
      <h1 className="text-2xl font-bold mb-4">Contact Us</h1>
      <p>Email: support@example.com</p>
      <p>Phone: +1 234 567 8901</p>
    </div>
  );
};

export default ContactUs;
